-            Some(ref v) => v.clone(),
-            None => {
-                let v = get_ruby_version(&process).context("get Ruby version");
-                if let Err(e) = v {
-                    debug!(
-                        "[{}] Trying again to get ruby version. Last error was: {:?}",
-                        process.pid, e
