commit bb793655a29242cee45042a15a97bc89217cfc57
Author: Adam Jensen <adam@acj.sh>
Date:   Sun Feb 5 07:35:36 2023 -0500

    Treat the thread ID as an optional/best-effort field

    Its type has always been Option<_>, but we've been treating it as a required field and skipping stack traces if we couldn't get it. Treating it as optional should help with issues like #376.
---
 src/core/ruby_version.rs | 17 +++++++++++++++--
 1 file changed, 15 insertions(+), 2 deletions(-)

diff --git a/src/core/ruby_version.rs b/src/core/ruby_version.rs
index 32aa0b9..1221443 100644
--- a/src/core/ruby_version.rs
+++ b/src/core/ruby_version.rs
@@ -350,7 +350,13 @@ macro_rules! get_stack_trace(
                 return Ok(StackTrace {
                     pid: Some(pid),
                     trace: vec!(StackFrame::unknown_c_function()),
-                    thread_id: Some(get_thread_id(&thread, source)?),
+                    thread_id: match get_thread_id(&thread, source) {
+                        Ok(tid) => Some(tid),
+                        Err(e) => {
+                            debug!("Couldn't get thread ID: {}", e);
+                            None
+                        },
+                    },
                     time: Some(SystemTime::now())
                 });
             }
@@ -401,7 +407,14 @@ macro_rules! get_stack_trace(
                     }
                 }
             }
-            Ok(StackTrace{trace, pid: Some(pid), thread_id: Some(get_thread_id(&thread, source)?), time: Some(SystemTime::now())})
+            let thread_id = match get_thread_id(&thread, source) {
+                Ok(tid) => Some(tid),
+                Err(e) => {
+                    debug!("Couldn't get thread ID: {}", e);
+                    None
+                },
+            };
+            Ok(StackTrace{trace, pid: Some(pid), thread_id, time: Some(SystemTime::now())})
         }

         use proc_maps::{maps_contain_addr, MapRange};

